sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var result = {
        status: "success",
        entity_types: [],
    };

    try {
        // Parse labels — queryParams.label is already an array when sent multiple times
        var labels = [];
        if (request.queryParams.label) {
            for (var i = 0; i < request.queryParams.label.length; i++) {
                var trimmed = String(request.queryParams.label[i]).trim();
                if (trimmed) labels.push(trimmed);
            }
        }

        var limit = 100;
        var excludeSysIds = [];

        if (labels.length > 0) {
            // Query 1: All exact matches for any of the labels
            var exactGR = new GlideRecord('sys_db_object');
            exactGR.addQuery('label', 'IN', labels.join(','));
            exactGR.orderBy('label');
            exactGR.query();

            while (exactGR.next()) {
                excludeSysIds.push(exactGR.getUniqueValue());
                result.entity_types.push({
                    label: exactGR.label.getDisplayValue(),
                    name: exactGR.name.getDisplayValue(),
                    sys_id: exactGR.getUniqueValue()
                });
            }

            // Query 2: Fill remaining slots with CONTAINS matches
            var remaining = limit - result.entity_types.length;
            if (remaining > 0) {
                var containsGR = new GlideRecord('sys_db_object');
                var orCondition = containsGR.addQuery('label', 'CONTAINS', labels[0]);
                for (var j = 1; j < labels.length; j++) {
                    orCondition.addOrCondition('label', 'CONTAINS', labels[j]);
                }
                if (excludeSysIds.length > 0) {
                    containsGR.addQuery('sys_id', 'NOT IN', excludeSysIds.join(','));
                }
                containsGR.orderBy('label');
                containsGR.setLimit(remaining);
                containsGR.query();

                while (containsGR.next()) {
                    result.entity_types.push({
                        label: containsGR.label.getDisplayValue(),
                        name: containsGR.name.getDisplayValue(),
                        sys_id: containsGR.getUniqueValue()
                    });
                }
            }

        } else {
            var tableDefGR = new GlideRecord('sys_db_object');
            tableDefGR.orderBy('label');
            tableDefGR.setLimit(limit);
            tableDefGR.query();

            while (tableDefGR.next()) {
                result.entity_types.push({
                    label: tableDefGR.label.getDisplayValue(),
                    name: tableDefGR.name.getDisplayValue(),
                    sys_id: tableDefGR.getUniqueValue(),
                });
            }
        }

        response.setStatus(200);
        return result;

    } catch (e) {
        response.setStatus(400);
        return {
            status: "error",
            message: e.toString()
        };
    }
})(request, response);
